using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers;

public static class TestHelpers
{
    public static SchoolContext CreateInMemoryContext(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    public static void SeedStudents(SchoolContext context)
    {
        context.Students.AddRange(
            new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = new DateTime(2022, 9, 1) }
        );
        context.SaveChanges();
    }

    public static void SeedDepartments(SchoolContext context)
    {
        context.Departments.AddRange(
            new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = new DateTime(2007, 9, 1), RowVersion = new byte[] { 0 } },
            new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = new DateTime(2007, 9, 1), RowVersion = new byte[] { 0 } }
        );
        context.SaveChanges();
    }

    public static void SeedInstructors(SchoolContext context)
    {
        context.Instructors.AddRange(
            new Instructor { ID = 101, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = new DateTime(1995, 3, 11) },
            new Instructor { ID = 102, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = new DateTime(2002, 7, 6) }
        );
        context.SaveChanges();
    }

    public static void SeedCourses(SchoolContext context)
    {
        if (!context.Departments.Any())
            SeedDepartments(context);

        context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 }
        );
        context.SaveChanges();
    }

    public static void SeedFullData(SchoolContext context)
    {
        SeedInstructors(context);
        SeedDepartments(context);
        SeedCourses(context);
        SeedStudents(context);

        // Add enrollments
        context.Enrollments.AddRange(
            new Enrollment { EnrollmentID = 1, StudentID = 1, CourseID = 1050, Grade = Grade.A },
            new Enrollment { EnrollmentID = 2, StudentID = 1, CourseID = 4022, Grade = Grade.B }
        );

        // Add course assignments
        context.CourseAssignments.AddRange(
            new CourseAssignment { InstructorID = 101, CourseID = 1050 },
            new CourseAssignment { InstructorID = 102, CourseID = 4022 }
        );

        context.SaveChanges();
    }

    /// <summary>
    /// Drains any pending notifications from the static queue to ensure test isolation.
    /// </summary>
    public static void DrainNotificationQueue()
    {
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
        svc.Dispose();
    }
}

