using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _sut = new();

    public NotificationServiceTests()
    {
        // Drain any leftover notifications from other tests
        while (_sut.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        // Drain after test to clean up
        while (_sut.ReceiveNotification() != null) { }
        _sut.Dispose();
    }

    [Fact]
    public void SendNotification_WithDisplayName_EnqueuesWithCorrectMessage()
    {
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        var notification = _sut.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Contains("John Doe", notification.Message);
        Assert.Contains("created", notification.Message);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
    {
        _sut.SendNotification("Course", "42", EntityOperation.UPDATE);

        var notification = _sut.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Contains("ID: 42", notification.Message);
        Assert.Contains("updated", notification.Message);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "created")]
    [InlineData(EntityOperation.UPDATE, "updated")]
    [InlineData(EntityOperation.DELETE, "deleted")]
    public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedVerb)
    {
        _sut.SendNotification("Department", "5", "Engineering", operation, "TestUser");

        var notification = _sut.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal(operation.ToString(), notification.Operation);
        Assert.Contains(expectedVerb, notification.Message);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var result = _sut.ReceiveNotification();

        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_MultipleMessages_ReturnsFifoOrder()
    {
        _sut.SendNotification("A", "1", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", EntityOperation.UPDATE);
        _sut.SendNotification("C", "3", EntityOperation.DELETE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();
        var third = _sut.ReceiveNotification();
        var fourth = _sut.ReceiveNotification();

        Assert.Equal("A", first!.EntityType);
        Assert.Equal("B", second!.EntityType);
        Assert.Equal("C", third!.EntityType);
        Assert.Null(fourth);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory, but should not throw
        var exception = Record.Exception(() => _sut.MarkAsRead(999));
        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToRecentTime()
    {
        var before = DateTime.Now;
        _sut.SendNotification("Test", "1", EntityOperation.CREATE);
        var after = DateTime.Now;

        var notification = _sut.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.InRange(notification.CreatedAt, before, after);
    }

    [Fact]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        _sut.SendNotification("Test", "1", null, EntityOperation.CREATE, null);

        var notification = _sut.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        var svc = new NotificationService();
        var exception = Record.Exception(() =>
        {
            svc.Dispose();
            svc.Dispose();
        });
        Assert.Null(exception);
    }
}

