namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    private static IQueryable<int> CreateSource(int count)
    {
        return Enumerable.Range(1, count).AsQueryable();
    }

    [Fact]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.Equal(10, result.Count);
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(1, result.First());
        Assert.Equal(10, result.Last());
    }

    [Fact]
    public void Create_MiddlePage_ReturnsCorrectItems()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 10);

        Assert.Equal(10, result.Count);
        Assert.Equal(2, result.PageIndex);
        Assert.Equal(11, result.First());
        Assert.Equal(20, result.Last());
    }

    [Fact]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 10);

        Assert.Equal(5, result.Count);
        Assert.Equal(3, result.PageIndex);
        Assert.Equal(21, result.First());
        Assert.Equal(25, result.Last());
    }

    [Fact]
    public void Create_SinglePage_ReturnsAllItems()
    {
        var source = CreateSource(5);

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.Equal(5, result.Count);
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(1, result.TotalPages);
    }

    [Fact]
    public void Create_ExactlyFillsPages_CalculatesTotalPagesCorrectly()
    {
        var source = CreateSource(20);

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.Equal(2, result.TotalPages);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.Empty(result);
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(0, result.TotalPages);
    }

    [Theory]
    [InlineData(1, false, true)]   // First page: no previous, has next
    [InlineData(2, true, true)]    // Middle page: has both
    [InlineData(3, true, false)]   // Last page: has previous, no next
    public void HasPreviousPage_HasNextPage_ReturnsCorrectValues(int pageIndex, bool expectedHasPrev, bool expectedHasNext)
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, pageIndex, pageSize: 10);

        Assert.Equal(expectedHasPrev, result.HasPreviousPage);
        Assert.Equal(expectedHasNext, result.HasNextPage);
    }

    [Fact]
    public void Constructor_SetsPropertiesCorrectly()
    {
        var items = new List<string> { "a", "b", "c" };

        var list = new PaginatedList<string>(items, count: 30, pageIndex: 2, pageSize: 10);

        Assert.Equal(2, list.PageIndex);
        Assert.Equal(3, list.TotalPages);
        Assert.Equal(3, list.Count);
        Assert.Contains("a", list);
        Assert.Contains("b", list);
        Assert.Contains("c", list);
    }

    [Fact]
    public void TotalPages_RoundsUp()
    {
        // 11 items with page size 10 = 2 pages
        var list = new PaginatedList<int>(new List<int> { 1 }, count: 11, pageIndex: 1, pageSize: 10);

        Assert.Equal(2, list.TotalPages);
    }
}

