using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _sut;

    public StudentsControllerTests()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateInMemoryContext();
        _sut = new StudentsController(_context);
    }

    public void Dispose()
    {
        TestHelpers.DrainNotificationQueue();
        _sut.Dispose();
        _context.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = new DateTime(2022, 9, 1) },
            new Student { ID = 4, FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = new DateTime(2019, 9, 1) }
        );
        _context.SaveChanges();
    }

    #region Index

    [Fact]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        SeedStudents();

        var result = _sut.Index(null, null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Alexander", model.First().LastName);
    }

    [Fact]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        SeedStudents();

        var result = _sut.Index("name_desc", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Barzdukas", model.First().LastName);
    }

    [Fact]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        SeedStudents();

        var result = _sut.Index("Date", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Barzdukas", model.First().LastName); // 2019 is earliest
    }

    [Fact]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        SeedStudents();

        var result = _sut.Index("date_desc", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Anand", model.First().LastName); // 2022 is latest
    }

    [Fact]
    public void Index_SearchFilter_FiltersStudentsByLastName()
    {
        SeedStudents();

        var result = _sut.Index(null, null, "Alex", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Alexander", model.First().LastName);
    }

    [Fact]
    public void Index_SearchFilter_FiltersStudentsByFirstName()
    {
        SeedStudents();

        var result = _sut.Index(null, null, "Meredith", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Alonso", model.First().LastName);
    }

    [Fact]
    public void Index_SearchString_ResetsPageToOne()
    {
        SeedStudents();

        var result = _sut.Index(null, null, "Alex", 3);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_NoSearchString_UsesCurrentFilter()
    {
        SeedStudents();

        var result = _sut.Index(null, "Alex", null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Index_SetsViewBagProperties()
    {
        SeedStudents();

        _sut.Index("Date", null, "test", null);

        Assert.Equal("Date", _sut.ViewBag.CurrentSort);
        Assert.Equal("date_desc", _sut.ViewBag.DateSortParm);
        Assert.Equal("", _sut.ViewBag.NameSortParm);
        Assert.Equal("test", _sut.ViewBag.CurrentFilter);
    }

    [Fact]
    public void Index_EmptySortOrder_SetsNameSortParmToDesc()
    {
        SeedStudents();

        _sut.Index(null, null, null, null);

        Assert.Equal("name_desc", _sut.ViewBag.NameSortParm);
        Assert.Equal("Date", _sut.ViewBag.DateSortParm);
    }

    #endregion

    #region Details

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsStudentWithEnrollments()
    {
        TestHelpers.SeedDepartments(_context);
        TestHelpers.SeedCourses(_context);
        _context.Students.Add(new Student { ID = 10, FirstMidName = "Test", LastName = "Student", EnrollmentDate = DateTime.Today });
        _context.SaveChanges();
        _context.Enrollments.Add(new Enrollment { StudentID = 10, CourseID = 1050, Grade = Grade.A });
        _context.SaveChanges();

        var result = _sut.Details(10);

        var viewResult = Assert.IsType<ViewResult>(result);
        var student = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Student", student.LastName);
        Assert.Single(student.Enrollments);
    }

    #endregion

    #region Create

    [Fact]
    public void Create_Get_ReturnsViewWithStudentAndTodayDate()
    {
        var result = _sut.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        var student = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal(DateTime.Today, student.EnrollmentDate);
    }

    [Fact]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            FirstMidName = "New",
            LastName = "Student",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = _sut.Create(student);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Single(_context.Students);
    }

    [Fact]
    public void Create_Post_MinDateEnrollment_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Bad",
            LastName = "Date",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _sut.Create(student);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.False(_sut.ModelState.IsValid);
        Assert.True(_sut.ModelState.ContainsKey("EnrollmentDate"));
