using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class DepartmentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly DepartmentsController _sut;

    public DepartmentsControllerTests()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateInMemoryContext();
        _sut = new DepartmentsController(_context);
    }

    public void Dispose()
    {
        TestHelpers.DrainNotificationQueue();
        _sut.Dispose();
        _context.Dispose();
    }

    private void SeedDepartmentsWithInstructor()
    {
        _context.Instructors.Add(new Instructor { ID = 1, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = new DateTime(1995, 3, 11) });
        _context.SaveChanges();
        _context.Departments.AddRange(
            new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = new DateTime(2007, 9, 1), InstructorID = 1, RowVersion = new byte[] { 0 } },
            new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = new DateTime(2007, 9, 1), RowVersion = new byte[] { 0 } }
        );
        _context.SaveChanges();
    }

    #region Index

    [Fact]
    public void Index_ReturnsViewWithDepartments()
    {
        SeedDepartmentsWithInstructor();

        var result = _sut.Index();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<IEnumerable<Department>>(viewResult.Model);
        Assert.Equal(2, model.Count());
    }

    [Fact]
    public void Index_NoDepartments_ReturnsEmptyList()
    {
        var result = _sut.Index();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<IEnumerable<Department>>(viewResult.Model);
        Assert.Empty(model);
    }

    #endregion

    #region Details

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_NonexistentId_ReturnsNotFound()
    {
        var result = _sut.Details(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        SeedDepartmentsWithInstructor();

        var result = _sut.Details(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var department = Assert.IsType<Department>(viewResult.Model);
        Assert.Equal("English", department.Name);
    }

    #endregion

    #region Create

    [Fact]
    public void Create_Get_ReturnsViewWithInstructorSelectList()
    {
        SeedDepartmentsWithInstructor();

        var result = _sut.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.NotNull(_sut.ViewBag.InstructorID);
    }

    [Fact]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        SeedDepartmentsWithInstructor();
        var department = new Department
        {
            Name = "Science",
            Budget = 200000,
            StartDate = new DateTime(2023, 9, 1),
            InstructorID = 1
        };

        var result = _sut.Create(department);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Equal(3, _context.Departments.Count());
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsViewWithSelectList()
    {
        SeedDepartmentsWithInstructor();
        _sut.ModelState.AddModelError("Name", "Required");
        var department = new Department { InstructorID = 1 };

        var result = _sut.Create(department);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.NotNull(_sut.ViewBag.InstructorID);
    }

    #endregion

    #region Edit

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Edit((int?)null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_NonexistentId_ReturnsNotFound()
    {
        var result = _sut.Edit(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithDepartment()
    {
        SeedDepartmentsWithInstructor();

        var result = _sut.Edit(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var department = Assert.IsType<Department>(viewResult.Model);
        Assert.Equal("English", department.Name);
        Assert.NotNull(_sut.ViewBag.InstructorID);
    }

    [Fact]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        SeedDepartmentsWithInstructor();
        _context.ChangeTracker.Clear();

        var department = new Department
        {
            DepartmentID = 1,
            Name = "Updated English",
            Budget = 400000,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = 1,
            RowVersion = new byte[] { 0 }
        };

        var result = _sut.Edit(department);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        SeedDepartmentsWithInstructor();
        _sut.ModelState.AddModelError("Name", "Required");
        var department = new Department { DepartmentID = 1, InstructorID = 1 };

        var result = _sut.Edit(department);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.NotNull(_sut.ViewBag.InstructorID);
    }

    #endregion

    #region Delete

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_NonexistentId_ReturnsNotFound()
    {
        var result = _sut.Delete(999);

        Assert.IsType<NotFoundResult>(result);
    }

