using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly Mock<IWebHostEnvironment> _mockEnv;
    private readonly Mock<ILogger<CoursesController>> _mockLogger;
    private readonly CoursesController _sut;
    private readonly string _tempDir;

    public CoursesControllerTests()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateInMemoryContext();
        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockLogger = new Mock<ILogger<CoursesController>>();

        _tempDir = Path.Combine(Path.GetTempPath(), "contoso_test_" + Guid.NewGuid());
        Directory.CreateDirectory(_tempDir);
        _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
        _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

        _sut = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
    }

    public void Dispose()
    {
        TestHelpers.DrainNotificationQueue();
        _sut.Dispose();
        _context.Dispose();
        if (Directory.Exists(_tempDir))
        {
            try { Directory.Delete(_tempDir, true); } catch { }
        }
    }

    private void SeedData()
    {
        TestHelpers.SeedDepartments(_context);
        _context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 }
        );
        _context.SaveChanges();
    }

    #region Index

    [Fact]
    public void Index_ReturnsViewWithCourses()
    {
        SeedData();

        var result = _sut.Index();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<IEnumerable<Course>>(viewResult.Model);
        Assert.Equal(2, model.Count());
    }

    [Fact]
    public void Index_NoCourses_ReturnsEmptyList()
    {
        var result = _sut.Index();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<IEnumerable<Course>>(viewResult.Model);
        Assert.Empty(model);
    }

    #endregion

    #region Details

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        SeedData();

        var result = _sut.Details(1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var course = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", course.Title);
        Assert.NotNull(course.Department);
    }

    #endregion

    #region Create

    [Fact]
    public void Create_Get_ReturnsViewWithDepartmentSelectList()
    {
        SeedData();

        var result = _sut.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.NotNull(_sut.ViewBag.DepartmentID);
    }

    [Fact]
    public void Create_Post_ValidCourse_NoFile_RedirectsToIndex()
    {
        SeedData();
        var course = new Course { CourseID = 9999, Title = "New Course", Credits = 3, DepartmentID = 1 };

        var result = _sut.Create(course, null!);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.NotNull(_context.Courses.Find(9999));
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        SeedData();
        _sut.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 8888, DepartmentID = 1 };

        var result = _sut.Create(course, null!);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.NotNull(_sut.ViewBag.DepartmentID);
    }

    [Fact]
    public void Create_Post_ValidFile_UploadsAndSavesPath()
    {
        SeedData();
        var mockFile = CreateMockFile("test.jpg", 1024);
        var course = new Course { CourseID = 7777, Title = "With Image", Credits = 3, DepartmentID = 1 };

        var result = _sut.Create(course, mockFile.Object);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        var saved = _context.Courses.Find(7777);
        Assert.NotNull(saved);
        Assert.StartsWith("/Uploads/TeachingMaterials/", saved!.TeachingMaterialImagePath);
    }

    [Theory]
    [InlineData(".exe")]
    [InlineData(".pdf")]
    [InlineData(".doc")]
    public void Create_Post_InvalidFileExtension_ReturnsViewWithError(string extension)
    {
        SeedData();
        var mockFile = CreateMockFile($"test{extension}", 1024);
        var course = new Course { CourseID = 6666, Title = "Bad File", Credits = 3, DepartmentID = 1 };

        var result = _sut.Create(course, mockFile.Object);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.True(_sut.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_FileTooLarge_ReturnsViewWithError()
    {
        SeedData();
        var mockFile = CreateMockFile("large.jpg", 6 * 1024 * 1024); // 6MB > 5MB limit
        var course = new Course { CourseID = 5555, Title = "Big File", Credits = 3, DepartmentID = 1 };

        var result = _sut.Create(course, mockFile.Object);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.True(_sut.ModelState.ContainsKey("teachingMaterialImage"));
    }

    #endregion

    #region Edit

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Edit((int?)null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_NonexistentId_ReturnsNotFound()
    {
        var result = _sut.Edit(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithCourse()
    {
        SeedData();

        var result = _sut.Edit(1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var course = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", course.Title);
        Assert.NotNull(_sut.ViewBag.DepartmentID);
    }

    [Fact]
    public void Edit_Post_ValidCourse_NoFile_RedirectsToIndex()
    {
        SeedData();
        _context.ChangeTracker.Clear();
        var course = new Course { CourseID = 1050, Title = "Updated Chemistry", Credits = 4, DepartmentID = 1 };

        var result = _sut.Edit(course, null!);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        SeedData();
        _sut.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1050, DepartmentID = 1 };

        var result = _sut.Edit(course, null!);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.NotNull(_sut.ViewBag.DepartmentID);
    }

    [Fact]
    public void Edit_Post_ValidFile_UploadsNewImage()
    {
        SeedData();
        _context.ChangeTracker.Clear();
        var mockFile = CreateMockFile("new_image.png", 2048);
        var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };

        var result = _sut.Edit(course, mockFile.Object);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidFileExtension_ReturnsViewWithError()
    {
        SeedData();
        var mockFile = CreateMockFile("bad.txt", 1024);
        var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };

        var result = _sut.Edit(course, mockFile.Object);

        Assert.True(_sut.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Edit_Post_FileTooLarge_ReturnsViewWithError()
    {
        SeedData();
        var mockFile = CreateMockFile("big.jpg", 6 * 1024 * 1024);
        var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };

        var result = _sut.Edit(course, mockFile.Object);

        Assert.True(_sut.ModelState.ContainsKey("teachingMaterialImage"));
    }

    #endregion

    #region Delete

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithCourse()
    {
        SeedData();

        var result = _sut.Delete(1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var course = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", course.Title);
    }

    [Fact]
    public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
    {
        SeedData();

        var result = _sut.DeleteConfirmed(1050);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Null(_context.Courses.Find(1050));
    }

    [Fact]
    public void DeleteConfirmed_CourseWithImage_DeletesImageFile()
    {
        SeedData();
        var uploadsPath = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
        Directory.CreateDirectory(uploadsPath);
        var imagePath = Path.Combine(uploadsPath, "test_image.jpg");
        File.WriteAllText(imagePath, "fake image content");

        var course = _context.Courses.Find(1050)!;
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
        _context.SaveChanges();

        var result = _sut.DeleteConfirmed(1050);

        Assert.IsType<RedirectToActionResult>(result);
        Assert.False(File.Exists(imagePath));
    }

    #endregion

    #region Helpers

    private static Mock<IFormFile> CreateMockFile(string fileName, long length)
    {
        var mock = new Mock<IFormFile>();
        mock.Setup(f => f.FileName).Returns(fileName);
        mock.Setup(f => f.Length).Returns(length);
        mock.Setup(f => f.CopyTo(It.IsAny<Stream>()));
        return mock;
    }

    #endregion
}

