using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly InstructorsController _sut;

    public InstructorsControllerTests()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateInMemoryContext();
        _sut = new InstructorsController(_context);
    }

    public void Dispose()
    {
        TestHelpers.DrainNotificationQueue();
        _sut.Dispose();
        _context.Dispose();
    }

    private void SeedFullData()
    {
        var instructor1 = new Instructor
        {
            ID = 1,
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = new DateTime(1995, 3, 11),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
        };
        var instructor2 = new Instructor
        {
            ID = 2,
            FirstMidName = "Fadi",
            LastName = "Fakhouri",
            HireDate = new DateTime(2002, 7, 6),
            CourseAssignments = new List<CourseAssignment>()
        };

        _context.Instructors.AddRange(instructor1, instructor2);
        _context.SaveChanges();

        _context.Departments.AddRange(
            new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = new DateTime(2007, 9, 1), InstructorID = 1, RowVersion = new byte[] { 0 } },
            new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = new DateTime(2007, 9, 1), RowVersion = new byte[] { 0 } }
        );
        _context.SaveChanges();

        _context.Courses.AddRange(
            new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            },
            new Course
            {
                CourseID = 4022,
                Title = "Microeconomics",
                Credits = 3,
                DepartmentID = 2,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            }
        );
        _context.SaveChanges();

        _context.CourseAssignments.Add(new CourseAssignment { InstructorID = 1, CourseID = 1050 });
        _context.SaveChanges();

        _context.Students.Add(new Student { ID = 1, FirstMidName = "Test", LastName = "Student", EnrollmentDate = DateTime.Today });
        _context.SaveChanges();

        _context.Enrollments.Add(new Enrollment { EnrollmentID = 1, StudentID = 1, CourseID = 1050, Grade = Grade.A });
        _context.SaveChanges();
    }

    #region Index

    [Fact]
    public void Index_NoSelection_ReturnsViewWithAllInstructors()
    {
        SeedFullData();

        var result = _sut.Index(null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<ContosoUniversity.Models.SchoolViewModels.InstructorIndexData>(viewResult.Model);
        Assert.Equal(2, model.Instructors.Count());
        Assert.Null(model.Courses);
        Assert.Null(model.Enrollments);
    }

    [Fact]
    public void Index_WithInstructorSelected_ShowsCourses()
    {
        SeedFullData();

        var result = _sut.Index(1, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<ContosoUniversity.Models.SchoolViewModels.InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Courses);
        Assert.Single(model.Courses);
        Assert.Equal("Chemistry", model.Courses.First().Title);
    }

    [Fact]
    public void Index_WithCourseSelected_ShowsEnrollments()
    {
        SeedFullData();

        var result = _sut.Index(1, 1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<ContosoUniversity.Models.SchoolViewModels.InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Enrollments);
        Assert.Single(model.Enrollments);
    }

    #endregion

    #region Details

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_NonexistentId_ReturnsNotFound()
    {
        var result = _sut.Details(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        SeedFullData();

        var result = _sut.Details(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var instructor = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal("Abercrombie", instructor.LastName);
    }

    #endregion

    #region Create

    [Fact]
    public void Create_Get_ReturnsViewWithCourseData()
    {
        SeedFullData();

        var result = _sut.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        var instructor = Assert.IsType<Instructor>(viewResult.Model);
        Assert.NotNull(instructor.CourseAssignments);
        Assert.NotNull(_sut.ViewBag.Courses);
    }

    [Fact]
    public void Create_Post_ValidInstructor_NoCourses_RedirectsToIndex()
    {
        SeedFullData();
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _sut.Create(instructor, null!);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void Create_Post_WithSelectedCourses_AssignsCourses()
    {
        SeedFullData();
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = new DateTime(2023, 1, 1)
        };
        var selectedCourses = new[] { "1050", "4022" };

        var result = _sut.Create(instructor, selectedCourses);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        var saved = _context.Instructors.Include(Microsoft.EntityFrameworkCore.EntityFrameworkQueryableExtensions.Include)
            .SingleOrDefault(i => i.LastName == "Instructor");
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        SeedFullData();
        _sut.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _sut.Create(instructor, null!);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.NotNull(_sut.ViewBag.Courses);
    }

    #endregion

    #region Edit

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Edit((int?)null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithInstructorAndCourseData()
    {
        SeedFullData();

        var result = _sut.Edit(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var instructor = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal("Abercrombie", instructor.LastName);
        Assert.NotNull(_sut.ViewBag.Courses);
    }

    #endregion

    #region Delete

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_NonexistentId_ReturnsNotFound()
    {
        var result = _sut.Delete(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithInstructor()
    {
        SeedFullData();

        var result = _sut.Delete(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var instructor = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal("Abercrombie", instructor.LastName);
    }

    [Fact]
    public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
    {
        SeedFullData();

        var result = _sut.DeleteConfirmed(1);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Null(_context.Instructors.Find(1));
    }

    [Fact]
    public void DeleteConfirmed_InstructorIsDepartmentAdmin_ClearsDepartmentAdmin()
    {
        SeedFullData();

        _sut.DeleteConfirmed(1);

        var department = _context.Departments.Find(1);
        Assert.NotNull(department);
        Assert.Null(department!.InstructorID);
    }

    #endregion
}

